SELECT MAX(flow) AS max_flow_rate
FROM outflows
WHERE site_id = 1;

SELECT flow
FROM outflows
WHERE site_id = 0 AND date(time) = '2021-09-04';

SELECT AVG(flow) AS average_flow_rate
FROM outflows
WHERE site_id = 0;

SELECT time
FROM outflows
WHERE outflow_id = 1;

SELECT MIN(flow) AS min_flow
FROM outflows
WHERE site_id = (SELECT site_id FROM sites WHERE site_name = 'Site A');

SELECT time, flow
FROM outflows
WHERE flow = (SELECT MAX(flow) FROM outflows);
